commits.content:
@tailwind base;
@tailwind components;
@tailwind utilities;

@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,500;0,600;0,700;1,400&family=DM+Sans:ital,opsz,wght@0,9..40,300;0,9..40,400;0,9..40,500;0,9..40,600;1,9..40,400&display=swap');

:root {
  --font-sans: 'DM Sans', system-ui, sans-serif;
  --font-display: 'Playfair Display', Georgia, serif;

  --bg: #ffffff;
  --bg-secondary: #fafafa;
  --bg-tertiary: #f8f9fa;
  --surface: #ffffff;
  --surface-raised: #fefefe;
  --border: #e5e7eb;
  --border-strong: #d1d5db;

  --text-primary: #111827;
  --text-secondary: #4b5563;
  --text-tertiary: #6b7280;
  --text-inverse: #ffffff;

  --accent: #14b8a6;
  --accent-hover: #0d9488;
  --accent-light: #f0fdfa;

  --success: #10b981;
  --warning: #f59e0b;
  --error: #ef4444;
  --info: #3b82f6;

  --radius-sm: 8px;
  --radius: 12px;
  --radius-lg: 16px;
  --radius-xl: 20px;
  --radius-full: 9999px;

  --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
  --shadow: 0 1px 3px 0 rgba(0, 0, 0, 0.1), 0 1px 2px 0 rgba(0, 0, 0, 0.06);
  --shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.1), 0 4px 6px -2px rgba(0, 0, 0, 0.05);
  --shadow-xl: 0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04);

  --transition: 250ms cubic-bezier(0.4, 0, 0.2, 1);
  --transition-slow: 350ms cubic-bezier(0.4, 0, 0.2, 1);
}



* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  scroll-behavior: smooth;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  font-family: var(--font-sans);
  background-color: var(--bg);
  color: var(--text-primary);
  line-height: 1.6;
  transition: background-color 0.3s, color 0.3s;
}

/* Typography */
.font-display { font-family: var(--font-display); }

h1, h2, h3, h4, h5, h6 {
  font-family: var(--font-display);
  line-height: 1.2;
  letter-spacing: -0.02em;
}

/* Scrollbar */
::-webkit-scrollbar { width: 6px; height: 6px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: var(--border-strong); border-radius: 3px; }
::-webkit-scrollbar-thumb:hover { background: var(--text-tertiary); }

/* Skeleton Loader */
.skeleton {
  background: linear-gradient(90deg, var(--bg-tertiary) 25%, var(--bg-secondary) 50%, var(--bg-tertiary) 75%);
  background-size: 200% 100%;
  animation: skeleton-shimmer 1.5s infinite;
  border-radius: var(--radius);
}

@keyframes skeleton-shimmer {
  0% { background-position: 200% 0; }
  100% { background-position: -200% 0; }
}

/* Focus styles */
:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
  border-radius: var(--radius-sm);
}

/* Selection */
::selection {
  background: var(--accent);
  color: var(--text-inverse);
}

/* Utility classes */
@layer components {
  .container-shop {
    @apply max-w-7xl mx-auto px-4 sm:px-6 lg:px-8;
  }

  .btn {
    @apply inline-flex items-center justify-center gap-2 font-medium rounded-[10px]
           transition-all duration-200 cursor-pointer select-none whitespace-nowrap
           disabled:opacity-50 disabled:cursor-not-allowed;
  }

  .btn-primary {
    @apply btn bg-[var(--accent)] text-[var(--text-inverse)] hover:bg-[var(--accent-hover)]
           px-6 py-3 text-sm tracking-wide;
  }

  .btn-secondary {
    @apply btn bg-[var(--bg-secondary)] text-[var(--text-primary)] hover:bg-[var(--bg-tertiary)]
           border border-[var(--border)] px-6 py-3 text-sm;
  }

  .btn-ghost {
    @apply btn text-[var(--text-secondary)] hover:bg-[var(--bg-secondary)] hover:text-[var(--text-primary)]
           px-4 py-2 text-sm;
  }

  .btn-sm { @apply px-4 py-2 text-sm; }
  .btn-lg { @apply px-8 py-4 text-base; }

  .card {
    @apply bg-[var(--surface)] border border-[var(--border)] rounded-[16px]
           shadow-[var(--shadow-sm)] transition-shadow duration-200;
  }

  .card-hover {
    @apply card hover:shadow-[var(--shadow)] hover:-translate-y-0.5 transition-all duration-300;
  }

  .input {
    @apply w-full px-4 py-3 bg-[var(--bg-secondary)] border border-[var(--border)]
           rounded-[10px] text-[var(--text-primary)] placeholder-[var(--text-tertiary)]
           focus:outline-none focus:ring-2 focus:ring-[var(--accent)] focus:ring-opacity-20
           focus:border-[var(--accent)] transition-all duration-200 text-sm;
  }

  .label {
    @apply block text-sm font-medium text-[var(--text-secondary)] mb-1.5;
  }

  .badge {
    @apply inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium;
  }

  .badge-success { @apply badge bg-green-100 text-green-800; }
  .badge-warning { @apply badge bg-amber-100 text-amber-800; }
  .badge-error { @apply badge bg-red-100 text-red-800; }
  .badge-info { @apply badge bg-blue-100 text-blue-800; }
  .badge-gray { @apply badge bg-gray-100 text-gray-700; }

  .divider {
    @apply border-t border-[var(--border)] my-6;
  }

  .section {
    @apply py-16 lg:py-24;
  }

  .section-title {
    @apply font-display text-3xl lg:text-4xl font-semibold text-[var(--text-primary)] tracking-tight;
  }

  .section-subtitle {
    @apply text-[var(--text-secondary)] mt-3 text-lg;
  }

  /* Product card */
  .product-card {
  @apply card-hover cursor-pointer overflow-hidden;
}

  .product-card-img {
    @apply relative overflow-hidden bg-[var(--bg-secondary)] aspect-square;
  }

  .product-card-img img {
    @apply w-full h-full object-cover transition-transform duration-500 group-hover:scale-105;
  }

  /* Admin sidebar */
  .admin-nav-item {
    @apply flex items-center gap-3 px-4 py-3 rounded-[10px] text-sm font-medium
           text-[var(--text-secondary)] hover:bg-[var(--bg-secondary)] hover:text-[var(--text-primary)]
           transition-all duration-150 cursor-pointer;
  }

  .admin-nav-item.active {
    @apply bg-[var(--accent)] text-[var(--text-inverse)] hover:bg-[var(--accent-hover)];
  }

  /* Page transition */
  .page-enter {
    @apply opacity-0 translate-y-2;
  }
  .page-enter-active {
    @apply opacity-100 translate-y-0 transition-all duration-300;
  }
}

/* Price styling */
.price {
  font-variant-numeric: tabular-nums;
  font-feature-settings: "tnum";
}

/* Animations */
@keyframes float {
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-8px); }
}

.animate-float { animation: float 3s ease-in-out infinite; }

@keyframes pulse-ring {
  0% { transform: scale(0.8); opacity: 1; }
  100% { transform: scale(2); opacity: 0; }
}

/* RTL support */
[dir="rtl"] {
  text-align: right;
}

/* Print */
@media print {
  nav, footer, .no-print { display: none !important; }
  .print-only { display: block !important; }
}
